        "stop-circle",
        "copy",
        "edit",
        "refresh",
        "tts",
        "loading",
        "close",
        "tag",
        "search",
        "library",
        "review",
        "explore",
        "focus",
        "lock",
        "prompt",
        "trash",
        "paper",
        "table",
        "folder",
        "folder-open",
        "user",
